// ============================================================
// pages/ApplyForm.jsx — Submit Application + Upload Documents
// ============================================================
// Step 1: Submit the application (creates DB record)
// Step 2: Upload required documents (up to 4 types)
// ============================================================

import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import { applicationAPI, uploadAPI } from "../services/api";
import { useAuth } from "../context/AuthContext";
import "../styles/dashboard.css";

// Required document types and their display labels
const DOC_TYPES = [
  { key: "pan_card",              label: "PAN Card",                icon: "🪪" },
  { key: "gst_certificate",       label: "GST Certificate",          icon: "📜" },
  { key: "bank_statement",        label: "Bank Statement",           icon: "🏦" },
  { key: "company_registration",  label: "Company Registration",     icon: "🏢" },
];

function ApplyForm() {
  const { logout } = useAuth();

  // Whether application has been submitted already
  const [submitted,       setSubmitted]       = useState(false);
  const [submitting,      setSubmitting]       = useState(false);
  const [submitError,     setSubmitError]      = useState("");

  // Track upload state per document type
  const [uploadStatus, setUploadStatus] = useState(
    DOC_TYPES.reduce((acc, d) => ({ ...acc, [d.key]: { file: null, done: false, error: "" } }), {})
  );

  // On mount: check if application already submitted
  useEffect(() => {
    applicationAPI.getStatus()
      .then(() => setSubmitted(true))  // 200 = already submitted
      .catch(() => setSubmitted(false));
  }, []);

  // ----- Step 1: Submit Application -----
  const handleSubmitApplication = async () => {
    setSubmitError("");
    setSubmitting(true);
    try {
      await applicationAPI.submit();
      setSubmitted(true);
    } catch (err) {
      const msg = err.response?.data?.detail;
      if (msg === "Application already submitted") {
        setSubmitted(true);  // It's fine, already done
      } else {
        setSubmitError(msg || "Failed to submit application");
      }
    } finally {
      setSubmitting(false);
    }
  };

  // ----- Step 2: Upload Document -----
  const handleFileSelect = (docType, file) => {
    setUploadStatus((prev) => ({
      ...prev,
      [docType]: { ...prev[docType], file, error: "" }
    }));
  };

  const handleUpload = async (docType) => {
    const { file } = uploadStatus[docType];
    if (!file) return;

    try {
      await uploadAPI.uploadDocument(docType, file);
      // Mark as done on success
      setUploadStatus((prev) => ({
        ...prev,
        [docType]: { ...prev[docType], done: true, error: "" }
      }));
    } catch (err) {
      setUploadStatus((prev) => ({
        ...prev,
        [docType]: { ...prev[docType], error: err.response?.data?.detail || "Upload failed" }
      }));
    }
  };

  return (
    <div className="dashboard-layout">
      <aside className="sidebar">
        <div className="sidebar-logo">PayOnboard</div>
        <ul className="sidebar-nav">
          <li><Link to="/dashboard">🏠 Dashboard</Link></li>
          <li><Link to="/apply" className="active">📄 Apply Now</Link></li>
          <li><Link to="/status">🔍 Track Status</Link></li>
        </ul>
        <div className="sidebar-footer">
          <button onClick={logout} style={{ background:"none", border:"none", color:"var(--color-text-secondary)", cursor:"pointer", fontSize:"0.875rem" }}>
            🚪 Logout
          </button>
        </div>
      </aside>

      <main className="main-content">
        <div className="topbar">
          <div>
            <h1 className="page-title">Onboarding Application</h1>
            <p className="page-subtitle">Submit your application and upload required documents</p>
          </div>
        </div>

        {/* ---- Step 1: Submit Application ---- */}
        <div className="card" style={{ marginBottom: "var(--space-xl)" }}>
          <h2 style={{ fontSize: "1.125rem", fontWeight: 600, marginBottom: "var(--space-sm)" }}>
            Step 1: Submit Application
          </h2>

          {submitted ? (
            <div className="alert alert-success">
              ✅ Application submitted successfully! Proceed to upload your documents below.
            </div>
          ) : (
            <>
              <p style={{ color: "var(--color-text-secondary)", fontSize: "0.9375rem", marginBottom: "var(--space-lg)" }}>
                Click the button below to formally submit your onboarding application.
                Our team will review it within 2-3 business days.
              </p>
              {submitError && <div className="alert alert-error">{submitError}</div>}
              <button
                className="btn btn-primary"
                onClick={handleSubmitApplication}
                disabled={submitting}
              >
                {submitting ? "Submitting..." : "Submit Application"}
              </button>
            </>
          )}
        </div>

        {/* ---- Step 2: Document Upload ---- */}
        <div className="card" id="documents">
          <h2 style={{ fontSize: "1.125rem", fontWeight: 600, marginBottom: "var(--space-sm)" }}>
            Step 2: Upload Documents
          </h2>
          <p style={{ color: "var(--color-text-secondary)", fontSize: "0.875rem", marginBottom: "var(--space-lg)" }}>
            {submitted
              ? "Upload the following documents. Accepted formats: PDF, JPG, PNG."
              : "Please submit your application first to enable document uploads."}
          </p>

          <div className="upload-grid">
            {DOC_TYPES.map(({ key, label, icon }) => {
              const state = uploadStatus[key];
              return (
                <div
                  key={key}
                  className={`upload-card ${state.done ? "uploaded" : ""}`}
                  onClick={() => !state.done && submitted && document.getElementById(`file-${key}`).click()}
                >
                  <div className="upload-icon">{state.done ? "✅" : icon}</div>
                  <div className="upload-label">{label}</div>

                  {state.done ? (
                    <div className="upload-hint" style={{ color: "var(--color-success)" }}>Uploaded!</div>
                  ) : (
                    <>
                      <div className="upload-hint">
                        {state.file ? state.file.name : "Click to select file"}
                      </div>
                      {state.error && <div className="upload-hint" style={{ color: "var(--color-danger)" }}>{state.error}</div>}
                    </>
                  )}

                  {/* Hidden file input — triggered by clicking the card */}
                  <input
                    id={`file-${key}`}
                    type="file"
                    accept=".pdf,.jpg,.jpeg,.png"
                    style={{ display: "none" }}
                    disabled={!submitted}
                    onChange={(e) => handleFileSelect(key, e.target.files[0])}
                  />

                  {/* Show Upload button once file is selected */}
                  {state.file && !state.done && (
                    <button
                      className="btn btn-primary"
                      style={{ marginTop: "var(--space-sm)", width: "100%", fontSize: "0.8125rem" }}
                      onClick={(e) => { e.stopPropagation(); handleUpload(key); }}
                    >
                      Upload
                    </button>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      </main>
    </div>
  );
}

export default ApplyForm;
